const config = require('../../../../config');
const sendVerificationEmail = require('../../../../helpers/send-verification-email');

async function recovery(ctx) {
  const redirectTo = ctx.state.l(config.verifyRoute);

  ctx.state.redirectTo = redirectTo;

  ctx.state.user[config.userFields.pendingRecovery] = true;
  await ctx.state.user.save();

  try {
    ctx.state.user = await sendVerificationEmail(ctx);
  } catch (err) {
    // wrap with try/catch to prevent redirect looping
    // (even though the koa redirect loop package will help here)
    if (!err.isBoom) return ctx.throw(err);
    ctx.logger.warn(err);
    if (ctx.accepts('html')) {
      ctx.flash('warning', err.message);
      ctx.redirect(ctx.state.l(config.loginRoute));
    } else {
      ctx.body = { message: err.message };
    }

    return;
  }

  if (ctx.accepts('html')) {
    ctx.redirect(redirectTo);
  } else {
    ctx.body = { redirectTo };
  }
}

module.exports = recovery;

import type { FetchDatabaseVersionOptions } from '@sequelize/core';
import { AbstractQueryInterface } from '@sequelize/core';
import { AbstractQueryInterfaceInternal } from '@sequelize/core/_non-semver-use-at-your-own-risk_/abstract-dialect/query-interface-internal.js';
import type { PostgresDialect } from './dialect.js';

export class PostgresQueryInterfaceTypescript<
  Dialect extends PostgresDialect = PostgresDialect,
> extends AbstractQueryInterface<Dialect> {
  readonly #internalQueryInterface: AbstractQueryInterfaceInternal;

  constructor(dialect: Dialect, internalQueryInterface?: AbstractQueryInterfaceInternal) {
    internalQueryInterface ??= new AbstractQueryInterfaceInternal(dialect);

    super(dialect, internalQueryInterface);
    this.#internalQueryInterface = internalQueryInterface;
  }

  async fetchDatabaseVersion(options?: FetchDatabaseVersionOptions): Promise<string> {
    const payload = await this.#internalQueryInterface.fetchDatabaseVersionRaw<{
      server_version: string;
    }>(options);

    return payload.server_version;
  }
}

import path from "node:path";

import {DMMF} from "@prisma/generator-helper";
import {toMap} from "@tsed/core";
import {Project} from "ts-morph";

import {DmmfEnum} from "../domain/DmmfEnum.js";
import {transformEnumsToEnums} from "../transform/transformEnumsToEnums.js";
import {generateDocuments} from "./generateDocuments.js";
import {generateOutputsBarrelFile} from "./generateOutputsBarrelFile.js";

export function generateEnums(dmmf: DMMF.Document, project: Project, baseDirPath: string): boolean {
  const enumsMap = toMap<string, DMMF.DatamodelEnum>(dmmf.datamodel.enums as any, "name");
  const enums = DmmfEnum.getEnums(dmmf, enumsMap);
  const enumsDirPath = path.resolve(baseDirPath, "enums");
  const enumsDirectory = project.createDirectory(enumsDirPath);
  const enumsIndex = enumsDirectory.createSourceFile(`index.ts`, undefined, {overwrite: true});

  const exportedEnums = generateDocuments<DmmfEnum>(enums, enumsDirectory, (document) => transformEnumsToEnums(document));

  if (enums.length) {
    return !!generateOutputsBarrelFile(enumsIndex, exportedEnums);
  }

  return false;
}
